import{_ as r,o as a,c as o,ae as n}from"./chunks/framework.C8MNLDzb.js";const c=JSON.parse('{"title":"《资治通鉴》典故","description":"","frontmatter":{},"headers":[],"relativePath":"diangu/shi/资治通鉴.md","filePath":"diangu/shi/资治通鉴.md"}'),s={name:"diangu/shi/资治通鉴.md"};function e(g,t,h,i,l,d){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="《资治通鉴》典故" tabindex="-1">《资治通鉴》典故 <a class="header-anchor" href="#《资治通鉴》典故" aria-label="Permalink to &quot;《资治通鉴》典故&quot;">​</a></h1><h2 id="玄武门之变" tabindex="-1">玄武门之变 <a class="header-anchor" href="#玄武门之变" aria-label="Permalink to &quot;玄武门之变&quot;">​</a></h2><p><strong>典故：</strong> 唐高祖武德九年六月，秦王李世民在长安玄武门设伏，杀死太子李建成和齐王李元吉，随后逼迫父亲李渊退位，是为唐太宗。 <strong>出处：</strong> 《资治通鉴·唐纪》 <strong>释义：</strong> 比喻宫廷政变或兄弟争权。</p><h2 id="土木堡之变" tabindex="-1">土木堡之变 <a class="header-anchor" href="#土木堡之变" aria-label="Permalink to &quot;土木堡之变&quot;">​</a></h2><p><strong>典故：</strong> 明英宗正统十四年，明军在土木堡被瓦剌军队击溃，英宗被俘，明军伤亡数十万人，是明朝由盛转衰的转折点。 <strong>出处：</strong> 《资治通鉴·明纪》 <strong>释义：</strong> 形容惨重的军事失败。</p><h2 id="推敲" tabindex="-1">推敲 <a class="header-anchor" href="#推敲" aria-label="Permalink to &quot;推敲&quot;">​</a></h2><p><strong>典故：</strong> 贾岛初次到京城参加科举，骑驴作诗，得句&quot;鸟宿池边树，僧敲月下门&quot;，初欲用&quot;推&quot;字，后改用&quot;敲&quot;字，在驴背上以手作推敲之势，不觉冲撞韩愈仪仗。 <strong>出处：</strong> 《资治通鉴·唐纪》 <strong>释义：</strong> 比喻斟酌字句，反复琢磨。</p><h2 id="赤壁之战" tabindex="-1">赤壁之战 <a class="header-anchor" href="#赤壁之战" aria-label="Permalink to &quot;赤壁之战&quot;">​</a></h2><p><strong>典故：</strong> 东汉末年，孙权、刘备联军在赤壁火烧曹军，大败曹操八十万大军，奠定三国鼎立的基础。周瑜采纳黄盖火攻之计，黄盖诈降，东南风起，火烧曹军战船。 <strong>出处：</strong> 《资治通鉴·汉纪》 <strong>释义：</strong> 历史上以少胜多的经典战役。</p><h2 id="闻鸡起舞" tabindex="-1">闻鸡起舞 <a class="header-anchor" href="#闻鸡起舞" aria-label="Permalink to &quot;闻鸡起舞&quot;">​</a></h2><p><strong>典故：</strong> 祖逖年轻时与刘琨同为司州主簿，常互相激励，立志报国。半夜听到鸡叫声，祖逖踢醒刘琨说：&quot;此非恶声也！&quot;两人起床舞剑练武。 <strong>出处：</strong> 《资治通鉴·晋纪》 <strong>释义：</strong> 比喻有志之士及时奋发。</p><h2 id="洛阳纸贵" tabindex="-1">洛阳纸贵 <a class="header-anchor" href="#洛阳纸贵" aria-label="Permalink to &quot;洛阳纸贵&quot;">​</a></h2><p><strong>典故：</strong> 左思《三都赋》写成后，豪贵之家竞相传抄，洛阳纸张供不应求，价格飞涨。 <strong>出处：</strong> 《资治通鉴·晋纪》 <strong>释义：</strong> 比喻作品风靡一时。</p><h2 id="淝水之战" tabindex="-1">淝水之战 <a class="header-anchor" href="#淝水之战" aria-label="Permalink to &quot;淝水之战&quot;">​</a></h2><p><strong>典故：</strong> 东晋时期，前秦苻坚率八十万大军南下攻晋，晋相谢安遣谢玄率八万北府兵迎战。晋军在淝水大破秦军，苻坚仓皇逃窜，风声鹤唳，草木皆兵。 <strong>出处：</strong> 《资治通鉴·晋纪》 <strong>释义：</strong> 历史上以少胜多的著名战例。</p><h2 id="三顾茅庐" tabindex="-1">三顾茅庐 <a class="header-anchor" href="#三顾茅庐" aria-label="Permalink to &quot;三顾茅庐&quot;">​</a></h2><p><strong>典故：</strong> 刘备三次前往隆中拜访诸葛亮，请他出山辅佐。诸葛亮在第三次刘备来访时终于出山，成为刘备的主要谋士。 <strong>出处：</strong> 《资治通鉴·蜀纪》 <strong>释义：</strong> 形容真诚恳切地一再邀请。</p><h2 id="曹操献刀" tabindex="-1">曹操献刀 <a class="header-anchor" href="#曹操献刀" aria-label="Permalink to &quot;曹操献刀&quot;">​</a></h2><p><strong>典故：</strong> 董卓专权，曹操借王允的七星宝刀欲刺杀董卓，事败后改名换姓潜逃出京。 <strong>出处：</strong> 《资治通鉴·汉纪》 <strong>释义：</strong> 比喻挺身而出、行刺强暴。</p><h2 id="挟天子以令诸侯" tabindex="-1">挟天子以令诸侯 <a class="header-anchor" href="#挟天子以令诸侯" aria-label="Permalink to &quot;挟天子以令诸侯&quot;">​</a></h2><p><strong>典故：</strong> 曹操将汉献帝迎至许昌，以皇帝名义发号施令，号令天下，诸侯虽然心中不服，但名义上难以抗拒。 <strong>出处：</strong> 《资治通鉴·汉纪》 <strong>释义：</strong> 比喻借领导人之名义发号施令。</p><h2 id="秦始皇焚书" tabindex="-1">秦始皇焚书 <a class="header-anchor" href="#秦始皇焚书" aria-label="Permalink to &quot;秦始皇焚书&quot;">​</a></h2><p><strong>典故：</strong> 秦始皇三十四年，丞相李斯建议焚烧《诗》《书》等典籍，禁止私学，以吏为师，统一思想。秦始皇下令执行，是为&quot;焚书坑儒&quot;。 <strong>出处：</strong> 《资治通鉴·秦纪》 <strong>释义：</strong> 比喻毁灭文化专制统治。</p><h2 id="党锢之祸" tabindex="-1">党锢之祸 <a class="header-anchor" href="#党锢之祸" aria-label="Permalink to &quot;党锢之祸&quot;">​</a></h2><p><strong>典故：</strong> 东汉桓帝、灵帝时期，宦官专权，士大夫集团与宦官集团反复斗争。宦官两次大范围逮捕、禁锢正直官员，是为&quot;党锢之祸&quot;。 <strong>出处：</strong> 《资治通鉴·汉纪》 <strong>释义：</strong> 指统治阶级内部的政治迫害。</p>',25)])])}const q=r(s,[["render",e]]);export{c as __pageData,q as default};
